const item = $input.first();
const triggerData = $('Telegram Trigger').first().json;

const binaryKeys = item.binary ? Object.keys(item.binary) : [];
const binaryKey = binaryKeys[0] || 'data';
const binaryData = item.binary?.[binaryKey];

let base64Image = '';
let mimeType = 'image/jpeg';

if (binaryData) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
  base64Image = buffer.toString('base64');
  mimeType = binaryData.mimeType || 'image/jpeg';
}

return [{
  json: {
    chat_id: triggerData.message.chat.id,
    user_name: triggerData.message.from.first_name || 'Usuário',
    contexto_usuario: triggerData.message.caption || '',
    imagem_base64: base64Image,
    mime_type: mimeType,
    timestamp: new Date().toISOString()
  }
}];

const response = $input.first().json;
const visionContent = response.choices?.[0]?.message?.content || '{}';
const dadosAnteriores = $('Preparar Dados').first().json;

let visionData;
try {
  let jsonStr = visionContent;
  const jsonMatch = visionContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) jsonStr = jsonMatch[1];

  const startIdx = jsonStr.indexOf('{');
  const endIdx = jsonStr.lastIndexOf('}');
  if (startIdx !== -1 && endIdx !== -1) {
    jsonStr = jsonStr.substring(startIdx, endIdx + 1);
  }

  visionData = JSON.parse(jsonStr.trim());
} catch (e) {
  visionData = {
    tipo: 'qualitativo',
    fonte: 'nao identificado',
    data_referencia: null,
    categoria: 'outro',
    contexto_qualitativo: visionContent,
    dados_numericos: [],
    resumo: '',
    texto_extraido: visionContent
  };
}

visionData.tipo = visionData.tipo || 'qualitativo';
visionData.dados_numericos = visionData.dados_numericos || [];
visionData.contexto_qualitativo = visionData.contexto_qualitativo || visionData.texto_extraido || '';

return [{
  json: {
    ...dadosAnteriores,
    vision: visionData,
    tipo_conteudo: visionData.tipo,
    tem_dados_numericos: visionData.dados_numericos.length > 0,
    tem_contexto_qualitativo: !!visionData.contexto_qualitativo
  }
}];

const dadosVision = $('Processar Vision').first().json;
const mapaResponse = $input.first().json;
const mapa = Array.isArray(mapaResponse) && mapaResponse.length > 0 
  ? mapaResponse[0].mapa_conhecimento 
  : {};

return [{
  json: {
    ...dadosVision,
    mapa_rag: mapa
  }
}];

