const response = $input.first().json;
const expertContent = response.choices?.[0]?.message?.content || '{}';
const dadosAnteriores = $('Combinar Dados').first().json;

let expertData;
try {
  let jsonStr = expertContent;
  const jsonMatch = expertContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) jsonStr = jsonMatch[1];

  const startIdx = jsonStr.indexOf('{');
  const endIdx = jsonStr.lastIndexOf('}');
  if (startIdx !== -1 && endIdx !== -1) {
    jsonStr = jsonStr.substring(startIdx, endIdx + 1);
  }

  expertData = JSON.parse(jsonStr.trim());
} catch (e) {
  expertData = {
    titulo: 'Documento sem título',
    categoria: 'A classificar',
    tags: [],
    resumo: dadosAnteriores.vision?.descricao_visual || '',
    prioridade: 'média',
    confianca: 'baixa',
    justificativa: 'Erro ao processar sugestão automática'
  };
}

const docId = 'doc_' + Date.now();

return [{
  json: {
    doc_id: docId,
    ...dadosAnteriores,
    sugestao: expertData
  }
}];

const dadosSugestao = $input.first().json;
const vision = dadosSugestao.vision || {};
const docId = dadosSugestao.doc_id;

let conteudo = vision.contexto_qualitativo || vision.texto_extraido || "";

if (vision.tipo === "misto" && vision.dados_numericos?.length > 0) {
  const metricasResumo = vision.dados_numericos.map(m =>
    `${m.metrica}: ${m.valor} ${m.unidade} (${m.periodo})`
  ).join("; ");
  conteudo += `\n\nMetricas relacionadas: ${metricasResumo}`;
}

function formatarData(dataRef) {
  if (!dataRef) return null;
  if (/^\d{4}$/.test(dataRef)) return `${dataRef}-01-01`;
  if (/^\d{4}-\d{2}-\d{2}$/.test(dataRef)) return dataRef;
  return null;
}

const bodyObj = {
  titulo: dadosSugestao.sugestao?.titulo || vision.resumo || vision.fonte || "Documento capturado",
  conteudo: conteudo,
  resumo: dadosSugestao.sugestao?.resumo || vision.resumo || "",
  fonte: vision.fonte || "captura_telegram",
  data_referencia: formatarData(vision.data_referencia),
  categoria: dadosSugestao.sugestao?.categoria || vision.categoria || "outro",
  subcategoria: dadosSugestao.sugestao?.subcategoria || null,
  tags: dadosSugestao.sugestao?.tags || [],
  tipo_conteudo: vision.tipo || "qualitativo",
  status: "rascunho",
  doc_id: docId
};

return [{
  json: {
    ...dadosSugestao,
    bodyJson: bodyObj
  }
}];

// FIX: Guard contra Supabase retornar array vazio
const dadosSupabase = $input.first().json;
const doc = Array.isArray(dadosSupabase) ? dadosSupabase[0] : dadosSupabase;

if (!doc || !doc.id) {
  throw new Error(`Supabase não retornou o documento salvo. Resposta: ${JSON.stringify(dadosSupabase).substring(0, 200)}`);
}

const docId = doc.id; // UUID do Supabase
const chatId = $("Telegram Trigger").first().json.message?.chat?.id || $("Processar Sugestão").first().json.chat_id;

const texto = `📋 Nova Sugestão do Agente RAG\n\n📌 Título: ${doc.titulo || "Sem título"}\n\n📁 Categoria: ${doc.categoria || "N/A"}\n📂 Subcategoria: ${doc.subcategoria || "N/A"}\n\n🏷️ Tags: ${(doc.tags || []).join(", ") || "Nenhuma"}\n\n📝 Resumo:\n${doc.resumo || "Sem resumo"}\n\n---\nID: ${docId}`;

const body = {
  chat_id: chatId,
  text: texto,
  reply_markup: {
    inline_keyboard: [
      [
        { text: "✅ Aprovar", callback_data: `approve_${docId}` },
        { text: "❌ Rejeitar", callback_data: `reject_${docId}` }
      ]
    ]
  }
};

return [{
  json: {
    doc_id: docId,
    chat_id: chatId,
    telegram_body: JSON.stringify(body)
  }
}];

const callback = $input.first().json;
const callbackData = callback.callback_query?.data || '';
const chatId = callback.callback_query?.message?.chat?.id || '';
const messageId = callback.callback_query?.message?.message_id || '';

const isApprove = callbackData.startsWith('approve_');
const isReject = callbackData.startsWith('reject_');
const docId = callbackData.replace('approve_', '').replace('reject_', '');

return [{
  json: {
    callback_data: callbackData,
    action: isApprove ? 'approve' : (isReject ? 'reject' : 'unknown'),
    doc_id: docId,
    chat_id: chatId,
    message_id: messageId,
    callback_query_id: callback.callback_query?.id
  }
}];

// FIX: Responde ao callback imediatamente para evitar o timeout de 10s do Telegram
// O botão ficaria girando indefinidamente sem isso.
const data = $input.first().json;
const BOT_TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${BOT_TOKEN}/answerCallbackQuery`,
    body: {
      callback_query_id: data.callback_query_id,
      text: data.action === 'approve' ? '⏳ Aprovando documento...' : '⏳ Rejeitando documento...',
      show_alert: false
    },
    json: true
  });
} catch (e) {
  // Callback pode ter expirado (> 10s), ignorar silenciosamente
}

// Passar dados adiante sem alteração
return [$input.first()];

const docs = $input.first().json;
const dadosAnteriores = $("Processar Callback").first().json;

const doc = Array.isArray(docs) ? docs[0] : docs;

if (!doc) {
  return [{json: {...dadosAnteriores, erro: "Documento não encontrado", documento: null}}];
}

const textoParaEmbedding = [doc.titulo || "", doc.resumo || "", doc.conteudo || ""].filter(t => t).join("\n\n");

return [{
  json: {
    ...dadosAnteriores,
    documento: doc,
    texto_embedding: textoParaEmbedding,
    documento_id: doc.id
  }
}];

const dados = $input.first().json;
const metricas = dados.vision.dados_numericos || [];
const fonte = dados.vision.fonte || 'captura_telegram';
const categoria = dados.vision.categoria || 'outro';

if (metricas.length === 0) {
  return [{ json: { skip: true, ...dados } }];
}

return metricas.map(item => ({
  json: {
    metrica: item.metrica,
    area: item.area || null,
    valor: parseFloat(String(item.valor).replace(/[^0-9.-]/g, '')) || 0,
    unidade: item.unidade || 'outro',
    periodo: item.periodo || new Date().toISOString().slice(0, 10),
    contexto: item.contexto || null,
    fonte: fonte,
    categoria: categoria,
    dados_originais: dados
  }
}));

